import type { StageInput, StageOutput, StageRuntime } from '../contracts.js';

export async function runStage(input: StageInput, runtime: StageRuntime): Promise<StageOutput> {
  const request = String(input.domain['inputs.user_text'] ?? input.domain['inputs.initial_user_text'] ?? '');
  return {
    result_json: JSON.stringify({ stage: input.stage, started: true, request_captured: request.length > 0, captured_at: runtime.now() }),
    items_json: JSON.stringify([input.stage + ':started']),
    digest: '',
  };
}
